import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';

const Members = () => {
    const [members, setMembers] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchMembers();
    }, []);

    const fetchMembers = async () => {
        try {
            const res = await api.get('/admin/users');
            setMembers(res.data.filter(u => u.role === 'member'));
        } catch (err) {
            console.error(err);
            toast.error('Failed to fetch members');
        } finally {
            setLoading(false);
        }
    };

    const toggleStatus = async (id, currentStatus) => {
        const newStatus = currentStatus === 'active' ? 'suspended' : 'active';
        try {
            await api.patch(`/admin/users/${id}/status`, { status: newStatus });
            setMembers(m => m.map(u => u._id === id ? { ...u, status: newStatus } : u));
            toast.success(`Member ${newStatus === 'active' ? 'activated' : 'suspended'}`);
        } catch (err) {
            toast.error('Failed to update status');
        }
    };

    return (
        <div className="fade-in">
            <div className="flex-between mb-6">
                <h2 className="page-title">Member Management</h2>
                <div style={{ color: 'var(--text-secondary)' }}>Total Members: {members.length}</div>
            </div>

            <div className="table-container">
                {loading ? (
                    <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-secondary)' }}>Loading members...</div>
                ) : (
                    <table>
                        <thead>
                            <tr>
                                <th>Name</th>
                                <th>Email</th>
                                <th>Phone</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {members.length === 0 ? (
                                <tr><td colSpan="5" style={{ textAlign: 'center' }}>No members found.</td></tr>
                            ) : (
                                members.map(u => (
                                    <tr key={u._id}>
                                        <td style={{ fontWeight: 500 }}>{u.fullName}</td>
                                        <td>{u.email}</td>
                                        <td>{u.phone || '-'}</td>
                                        <td>
                                            <span className={`status-badge status-${u.status}`}>
                                                {u.status}
                                            </span>
                                        </td>
                                        <td>
                                            <button
                                                onClick={() => toggleStatus(u._id, u.status)}
                                                className={`btn ${u.status === 'active' ? 'btn-danger' : 'btn-primary'}`}
                                                style={{ padding: '0.25rem 0.75rem', fontSize: '0.75rem' }}
                                            >
                                                {u.status === 'active' ? 'Suspend' : 'Activate'}
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default Members;
